-- back compat for old kwarg name
  
  begin;
    
        
            
                
                
            
                
                
            
        
    

    

    merge into MEDICORE.STAGING.stg_history as DBT_INTERNAL_DEST
        using MEDICORE.STAGING.stg_history__dbt_tmp as DBT_INTERNAL_SOURCE
        on (
                    DBT_INTERNAL_SOURCE.PHA_ID = DBT_INTERNAL_DEST.PHA_ID
                ) and (
                    DBT_INTERNAL_SOURCE."Date" = DBT_INTERNAL_DEST."Date"
                )

    
    when matched then update set
        "PHA_ID" = DBT_INTERNAL_SOURCE."PHA_ID","Date" = DBT_INTERNAL_SOURCE."Date","ESPECEFRF" = DBT_INTERNAL_SOURCE."ESPECEFRF","CHEQUEFRF" = DBT_INTERNAL_SOURCE."CHEQUEFRF","CB" = DBT_INTERNAL_SOURCE."CB","CENTRE" = DBT_INTERNAL_SOURCE."CENTRE","DIFFERE_POSITIF" = DBT_INTERNAL_SOURCE."DIFFERE_POSITIF","NB_DE_FACTURES" = DBT_INTERNAL_SOURCE."NB_DE_FACTURES","NB_DE_SUBRO" = DBT_INTERNAL_SOURCE."NB_DE_SUBRO","TVA_1" = DBT_INTERNAL_SOURCE."TVA_1","TVA_2" = DBT_INTERNAL_SOURCE."TVA_2","TVA_3" = DBT_INTERNAL_SOURCE."TVA_3","TVA_4" = DBT_INTERNAL_SOURCE."TVA_4","TVA_5" = DBT_INTERNAL_SOURCE."TVA_5","MARGE_REMBT" = DBT_INTERNAL_SOURCE."MARGE_REMBT","MARGE_NREMBT" = DBT_INTERNAL_SOURCE."MARGE_NREMBT","REMISE_ENCOMPTE" = DBT_INTERNAL_SOURCE."REMISE_ENCOMPTE","REMISE_ENLIGNE" = DBT_INTERNAL_SOURCE."REMISE_ENLIGNE","ENCOMPTE_POSITIF" = DBT_INTERNAL_SOURCE."ENCOMPTE_POSITIF","MUTUELLE" = DBT_INTERNAL_SOURCE."MUTUELLE","ESPECEEUR" = DBT_INTERNAL_SOURCE."ESPECEEUR","CHEQUEEUR" = DBT_INTERNAL_SOURCE."CHEQUEEUR","VIREMENT" = DBT_INTERNAL_SOURCE."VIREMENT","SUBROPARTASSURE" = DBT_INTERNAL_SOURCE."SUBROPARTASSURE","CONTROLE" = DBT_INTERNAL_SOURCE."CONTROLE","POINTSFIDEL" = DBT_INTERNAL_SOURCE."POINTSFIDEL","PARTICULIER" = DBT_INTERNAL_SOURCE."PARTICULIER","ENCOMPTEBL_POSITIF" = DBT_INTERNAL_SOURCE."ENCOMPTEBL_POSITIF","DIFFERE_NEGATIF" = DBT_INTERNAL_SOURCE."DIFFERE_NEGATIF","ENCOMPTE_NEGATIF" = DBT_INTERNAL_SOURCE."ENCOMPTE_NEGATIF","ENCOMPTEBL_NEGATIF" = DBT_INTERNAL_SOURCE."ENCOMPTEBL_NEGATIF","CA_RETRO_1" = DBT_INTERNAL_SOURCE."CA_RETRO_1","CA_RETRO_2" = DBT_INTERNAL_SOURCE."CA_RETRO_2","CA_RETRO_3" = DBT_INTERNAL_SOURCE."CA_RETRO_3","CA_RETRO_4" = DBT_INTERNAL_SOURCE."CA_RETRO_4","CA_RETRO_5" = DBT_INTERNAL_SOURCE."CA_RETRO_5","DMPOSITIF" = DBT_INTERNAL_SOURCE."DMPOSITIF","DMNEGATIF" = DBT_INTERNAL_SOURCE."DMNEGATIF","DMRETROPOSITIF" = DBT_INTERNAL_SOURCE."DMRETROPOSITIF","DMRETRONEGATIF" = DBT_INTERNAL_SOURCE."DMRETRONEGATIF","LOADED_AT" = DBT_INTERNAL_SOURCE."LOADED_AT"
    

    when not matched then insert
        ("PHA_ID", "Date", "ESPECEFRF", "CHEQUEFRF", "CB", "CENTRE", "DIFFERE_POSITIF", "NB_DE_FACTURES", "NB_DE_SUBRO", "TVA_1", "TVA_2", "TVA_3", "TVA_4", "TVA_5", "MARGE_REMBT", "MARGE_NREMBT", "REMISE_ENCOMPTE", "REMISE_ENLIGNE", "ENCOMPTE_POSITIF", "MUTUELLE", "ESPECEEUR", "CHEQUEEUR", "VIREMENT", "SUBROPARTASSURE", "CONTROLE", "POINTSFIDEL", "PARTICULIER", "ENCOMPTEBL_POSITIF", "DIFFERE_NEGATIF", "ENCOMPTE_NEGATIF", "ENCOMPTEBL_NEGATIF", "CA_RETRO_1", "CA_RETRO_2", "CA_RETRO_3", "CA_RETRO_4", "CA_RETRO_5", "DMPOSITIF", "DMNEGATIF", "DMRETROPOSITIF", "DMRETRONEGATIF", "LOADED_AT")
    values
        ("PHA_ID", "Date", "ESPECEFRF", "CHEQUEFRF", "CB", "CENTRE", "DIFFERE_POSITIF", "NB_DE_FACTURES", "NB_DE_SUBRO", "TVA_1", "TVA_2", "TVA_3", "TVA_4", "TVA_5", "MARGE_REMBT", "MARGE_NREMBT", "REMISE_ENCOMPTE", "REMISE_ENLIGNE", "ENCOMPTE_POSITIF", "MUTUELLE", "ESPECEEUR", "CHEQUEEUR", "VIREMENT", "SUBROPARTASSURE", "CONTROLE", "POINTSFIDEL", "PARTICULIER", "ENCOMPTEBL_POSITIF", "DIFFERE_NEGATIF", "ENCOMPTE_NEGATIF", "ENCOMPTEBL_NEGATIF", "CA_RETRO_1", "CA_RETRO_2", "CA_RETRO_3", "CA_RETRO_4", "CA_RETRO_5", "DMPOSITIF", "DMNEGATIF", "DMRETROPOSITIF", "DMRETRONEGATIF", "LOADED_AT")

